mapper.select:
SELECT s.sku_id AS skuId, s.spu_id AS spuId, s.sku_name AS skuName, s.sku_desc AS skuDesc, s.catalog_id AS catalogId, s.brand_id AS brandId, s.sku_default_img AS skuDefaultImg, s.sku_title AS skuTitle, s.sku_subtitle AS skuSubtitle, s.price AS price, s.sale_count AS saleCount, p.spu_name AS spuName, p.publish_status AS spuPublishStatus, ( SELECT GROUP_CONCAT( CONCAT(IFNULL(sa.attr_name, ''), ':', IFNULL(sa.attr_value, '')) ORDER BY sa.attr_sort SEPARATOR ' ' ) FROM pms_sku_sale_attr_value sa WHERE sa.sku_id = s.sku_id ) AS saleAttrText FROM pms_sku_info s INNER JOIN pms_spu_info p ON s.spu_id = p.id
AND p.publish_status = #{req.spuPublishStatus}
AND s.sku_name LIKE CONCAT('%', #{req.skuName}, '%')
AND p.spu_name LIKE CONCAT('%', #{req.spuName}, '%')
AND s.spu_id = #{req.spuId}
AND s.catalog_id = #{req.catalogId}
AND s.brand_id = #{req.brandId}
AND s.price >= #{req.minPrice}
AND s.price <= #{req.maxPrice}
ORDER BY s.sku_id DESC

mapper.update:
UPDATE pms_sku_info
SET sale_count = IFNULL(sale_count, 0) + #{quantity}
WHERE sku_id = #{skuId}

UPDATE pms_sku_info
SET sale_count = GREATEST(IFNULL(sale_count, 0) - #{quantity}, 0)
WHERE sku_id = #{skuId}
